import{_ as t,o as s,c as e,a2 as i}from"./chunks/framework.DGp-bpT-.js";const g=JSON.parse('{"title":"Настройка интеграции с Telegram","description":"","frontmatter":{},"headers":[],"relativePath":"guide/telegram-setup.md","filePath":"guide/telegram-setup.md","lastUpdated":1776149669000}'),l={name:"guide/telegram-setup.md"};function o(r,a,n,p,h,c){return s(),e("div",null,[...a[0]||(a[0]=[i(`<h1 id="настроика-интеграции-с-telegram" tabindex="-1">Настройка интеграции с Telegram <a class="header-anchor" href="#настроика-интеграции-с-telegram" aria-label="Permalink to &quot;Настройка интеграции с Telegram&quot;">​</a></h1><p>Интеграция SREBot с Telegram позволяет боту читать сообщения в вашем групповом чате, находить в них алерты от Alertmanager и автоматически отвечать готовым RCA-отчётом.</p><hr><h2 id="_1-создание-бота-через-botfather" tabindex="-1">1. Создание бота через @BotFather <a class="header-anchor" href="#_1-создание-бота-через-botfather" aria-label="Permalink to &quot;1. Создание бота через @BotFather&quot;">​</a></h2><ol><li><p>Откройте Telegram и найдите <strong>@BotFather</strong> — официального бота для управления ботами.</p></li><li><p>Отправьте команду <code>/newbot</code>.</p></li><li><p>BotFather попросит ввести <strong>отображаемое имя</strong> бота (например: <code>SREBot — Acme Prod</code>).</p></li><li><p>Затем введите <strong>username</strong> бота — он должен заканчиваться на <code>bot</code> (например: <code>acme_sre_bot</code>).</p></li><li><p>BotFather создаст бота и вернёт <strong>токен</strong> вида:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>123456789:AAFhd-xxxxxxxxxxxxxxxxxxxxxxxxxxxxxxx</span></span></code></pre></div><p>Сохраните этот токен — он понадобится на шаге настройки.</p></li></ol><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p><strong>Один инстанс на один токен:</strong> Telegram допускает только <strong>одно</strong> активное соединение (long-polling) для конкретного токена бота.</p><ul><li>Если запустить две копии SREBot с одним и тем же токеном, они будут «перехватывать» сообщения друг у друга, что приведет к непредсказуемой работе и потере алертов.</li><li>Если вам нужно мониторить разные кластеры или окружения независимо, <strong>создайте уникального бота для каждого инстанса SREBot</strong> и пригласите их всех в ваш инцидент-чат.</li></ul></div><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>Username бота будет виден всем участникам чата. Рекомендуем использовать что-то понятное команде, например <code>acme_sre_bot</code>.</p></div><hr><h2 id="_2-настроика-прав-бота-group-privacy" tabindex="-1">2. Настройка прав бота (Group Privacy) <a class="header-anchor" href="#_2-настроика-прав-бота-group-privacy" aria-label="Permalink to &quot;2. Настройка прав бота (Group Privacy)&quot;">​</a></h2><p>По умолчанию Telegram-боты в группах получают <strong>только сообщения, начинающиеся с <code>/</code></strong> (команды) или упоминания бота. Чтобы SREBot мог читать все сообщения (включая алерты от Alertmanager), нужно отключить режим Group Privacy.</p><ol><li>В диалоге с <strong>@BotFather</strong> отправьте <code>/mybots</code>.</li><li>Выберите вашего бота из списка.</li><li>Нажмите <strong>Bot Settings → Group Privacy</strong>.</li><li>Нажмите <strong>Turn off</strong>.</li><li>Убедитесь, что статус изменился на <code>Group Privacy is DISABLED</code>.</li></ol><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p>Без этого шага бот <strong>не будет видеть</strong> сообщения Alertmanager и никогда не запустит анализ.</p></div><hr><h2 id="_3-получение-chat-id-группового-чата" tabindex="-1">3. Получение Chat ID группового чата <a class="header-anchor" href="#_3-получение-chat-id-группового-чата" aria-label="Permalink to &quot;3. Получение Chat ID группового чата&quot;">​</a></h2><p>SREBot нужно сообщить ID конкретного чата, за которым он будет следить. Чтобы его узнать:</p><p><strong>Способ 1 — через @userinfobot:</strong></p><ol><li>Добавьте <a href="https://t.me/userinfobot" target="_blank" rel="noreferrer">@userinfobot</a> во временный чат или напишите ему в личку.</li><li>Перешлите в него любое сообщение из вашего инцидент-чата.</li><li>Бот ответит с данными отправителя и <code>Forwarded from chat</code> с числовым ID.</li></ol><p><strong>Способ 2 — через Telegram API:</strong></p><ol><li>Добавьте вашего бота в нужный чат.</li><li>Отправьте в чат любое сообщение.</li><li>Откройте в браузере:<div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://api.telegram.org/bot&lt;ВАШ_ТОКЕН&gt;/getUpdates</span></span></code></pre></div></li><li>В ответе найдите поле <code>&quot;chat&quot;: {&quot;id&quot;: -100123456789, ...}</code>.</li></ol><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>ID групповых чатов всегда <strong>отрицательный</strong> и начинается с <code>-100</code>. Например: <code>-1001234567890</code>.</p></div><hr><h2 id="_4-добавление-бота-в-чат" tabindex="-1">4. Добавление бота в чат <a class="header-anchor" href="#_4-добавление-бота-в-чат" aria-label="Permalink to &quot;4. Добавление бота в чат&quot;">​</a></h2><ol><li>Откройте нужный инцидент-чат в Telegram.</li><li>Нажмите на название чата → <strong>Добавить участника</strong>.</li><li>Найдите бота по его username и добавьте.</li><li>Убедитесь, что у бота есть права <strong>читать сообщения</strong> — для обычных групп это происходит автоматически после отключения Group Privacy (шаг 2).</li></ol><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>Если чат является <strong>супергруппой</strong> или <strong>каналом</strong> — добавьте бота как <strong>администратора</strong> с правом чтения сообщений. Это требуется для чтения сообщений из каналов (posted через Alertmanager webhook).</p></div><hr><h2 id="_5-настроика-бота-env" tabindex="-1">5. Настройка бота (Env) <a class="header-anchor" href="#_5-настроика-бота-env" aria-label="Permalink to &quot;5. Настройка бота (Env)&quot;">​</a></h2><p>После сбора всех данных добавьте их в ваш файл <code>.env</code> или в <code>values.yaml</code> Helm-чарта:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Токен бота от BotFather</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">TELEGRAM_BOT_TOKEN</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">123456789:AAFhd-xxxxxxxxxxxxxxxxxxxxxxxxxxxxxxx</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># ID вашего группового чата (отрицательное число)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">TELEGRAM_CHANNEL_ID</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">-1001234567890</span></span></code></pre></div><p>Или в <code>values.yaml</code>:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">config</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  telegramBotToken</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;123456789:AAFhd-xxxxxxxxxxxxxxxxxxxxxxxxxxxxxxx&quot;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  telegramChatId</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;-1001234567890&quot;</span></span></code></pre></div><hr><h2 id="как-это-работает-после-настроики" tabindex="-1">Как это работает после настройки <a class="header-anchor" href="#как-это-работает-после-настроики" aria-label="Permalink to &quot;Как это работает после настройки&quot;">​</a></h2><p>После запуска SREBot подключается к Telegram через <strong>long-polling</strong> и ждёт новых сообщений в указанном чате. При появлении алерта от Alertmanager бот:</p><ol><li>Парсит сообщение и извлекает метаданные алерта.</li><li>Проверяет дедупликацию — если такой алерт уже обрабатывается, пропускает его.</li><li>Отправляет в тред <strong>reply-заглушку</strong> <code>🔍 Analyzing...</code> на оригинальное сообщение.</li><li>Запускает AI-анализ и заменяет заглушку готовым RCA-отчётом.</li></ol>`,34)])])}const x=t(l,[["render",o]]);export{g as __pageData,x as default};
